inputs.script:
const c=(v)=>{const t=String(v==null?'':v).trim();return /^\{[a-zA-Z0-9_]+\}$/.test(t)?'':t;};
const url=c(arg0)||location.href;
const norm=(s)=>(s||'').replace(/ /g,' ').replace(/\s+/g,' ').trim();
const PREFIX='Open control menu for post by ';
const stripQ=(h)=>{if(!h)return '';try{const u=new URL(h,location.origin);return u.origin+u.pathname;}catch(e){return h;}};
const menu=document.querySelector('button[aria-label^="'+PREFIX+'"]');
let author='',author_url='',text='',card=null,bodyEl=null;
if(menu){author=norm((menu.getAttribute('aria-label')||'').slice(PREFIX.length));card=menu;for(let i=0;i<20;i++){if(!card.parentElement)break;card=card.parentElement;if(card.querySelector('button[aria-label="Comment"]'))break;}}
if(!card)card=document.querySelector('main')||document.body;
const box=card.querySelector('[data-testid="expandable-text-box"]');
if(box){bodyEl=box;text=norm(box.innerText);}
else{let best=null,bestLen=0;card.querySelectorAll('[dir="ltr"]').forEach((e)=>{const t=norm(e.innerText);if(t.length>bestLen&&t.length>30){best=e;bestLen=t.length;}});if(best){bodyEl=best;text=norm(best.innerText);}}
const alink=[...card.querySelectorAll('a[href*="/in/"],a[href*="/company/"]')].find((a)=>norm(a.innerText)===author)||card.querySelector('a[href*="/in/"],a[href*="/company/"]');
author_url=alink?stripQ(alink.getAttribute('href')):'';
const cardText=norm(card.innerText||'');
const wc=(re)=>{const m=cardText.match(re);return m?m[1].replace(/,/g,''):null;};
const bare=[];card.querySelectorAll('*').forEach((e)=>{if(e.childElementCount===0){const t=(e.innerText||'').trim();if(/^[\d,]{1,7}$/.test(t)){if(!bodyEl||((bodyEl.compareDocumentPosition(e)&Node.DOCUMENT_POSITION_FOLLOWING)&&!bodyEl.contains(e)))bare.push(t.replace(/,/g,''));}}});
const reactions=wc(/([\d,]+)\s*reactions?/i)||bare[0]||'0';
const comments_count=wc(/([\d,]+)\s*comments?/i)||bare[1]||'0';
const reposts=wc(/([\d,]+)\s*reposts?/i)||bare[2]||'0';
const comments=[];const allLtr=[...document.querySelectorAll('[dir="ltr"]')].map((e)=>({el:e,t:norm(e.innerText)})).filter((x)=>x.t.length>2);
let started=false;const seenC=new Set();
for(const x of allLtr){if(!started){if(x.t===text)started=true;continue;}if(x.t===text)continue;if(/^(Like|Reply|Comment|Repost|Send|Follow|More)$/i.test(x.t))continue;if(seenC.has(x.t))continue;seenC.add(x.t);let a=x.el,alab='';for(let i=0;i<8&&a;i++){a=a.parentElement;if(a&&a.querySelector){const al=a.querySelector('a[href*="/in/"]');if(al){alab=norm(al.innerText);break;}}}comments.push({author:alab||'',text:x.t.slice(0,400)});if(comments.length>=10)break;}
return {url:url,author:author,author_url:author_url,text:text,reactions:reactions,comments_count:comments_count,reposts:reposts,comments:comments};
